VERL training monitor oneshot check for run_1780019310. Execute: python3 -c "
import json, sys, os
from pathlib import Path
run_dir = Path('rllm_train/output/runs/run_1780019310')
jsonl = run_dir / 'verl_metrics.jsonl'
log = run_dir / 'training_log.txt'
if not jsonl.exists():
    print('ONESHOT: model loading, no metrics yet')
    if log.exists():
        tail = log.read_text()[-4096:]
        for kw in ['Traceback', 'CUDA out of memory', 'Killed', 'SIGTERM']:
            if kw in tail:
                print(f'DETECTED: {kw} in training log')
                break
    sys.exit(0)
steps = []
for line in jsonl.read_text().strip().split('\n'):
    if not line.strip(): continue
    try: steps.append(json.loads(line))
    except: pass
if not steps:
    print('ONESHOT: empty metrics')
    sys.exit(0)
last = steps[-1]
data = last['data']
s = last['step']
print(f'=== Step {s} ===')
metrics = [('Reward', 'critic/score/mean', '.4f'), ('R_max', 'critic/score/max', '.4f'), ('R_min', 'critic/score/min', '.4f'), ('Reward(KL)', 'critic/rewards/mean', '.4f'), ('Advantage', 'critic/advantages/mean', '.4f'), ('Adv_max', 'critic/advantages/max', '.4f'), ('pg_loss', 'actor/pg_loss', '+.4f'), ('grad_norm', 'actor/grad_norm', '.4f'), ('entropy', 'actor/entropy', '.4f'), ('clipfrac', 'actor/pg_clipfrac', '.4f'), ('ppo_kl', 'actor/ppo_kl', '.4f'), ('lr', 'actor/lr', '.2e'), ('resp_len', 'response_length/mean', '.0f'), ('resp_clip', 'response_length/clip_ratio', '.3f'), ('abort', 'response/aborted_ratio', '.3f'), ('turns', 'num_turns/mean', '.1f'), ('t_gen', 'timing_s/gen', '.1f'), ('t_update', 'timing_s/update_actor', '.1f'), ('t_step', 'timing_s/step', '.1f'), ('throughput', 'perf/throughput', '.0f'), ('epoch', 'training/epoch', '.2f'), ('mfu', 'perf/mfu/actor_infer', '.3f')]
for label, key, fmt in metrics:
    v = data.get(key)
    if v is not None: print(f'  {label:12s} = {v:{fmt}}')
n = len(steps)
scores = [s['data'].get('critic/score/mean', 0) for s in steps]
score_maxs = [s['data'].get('critic/score/max', 0) for s in steps]
score_mins = [s['data'].get('critic/score/min', 0) for s in steps]
grads = [s['data'].get('actor/grad_norm', 0) for s in steps]
ents = [s['data'].get('actor/entropy', 0) for s in steps]
advs = [s['data'].get('critic/advantages/mean', 0) for s in steps]
aborts = [s['data'].get('response/aborted_ratio', 0) for s in steps]
w = min(5, n)
alerts = []
if n >= 5 and all(g < 0.01 for g in grads[-w:]): alerts.append(('S0', 'no_learning_signal', f'grad_norm < 0.01 for {w} steps', grads[-w:]))
if n >= 3 and all(e < 0.01 for e in ents[-3:]): alerts.append(('S1', 'entropy_collapse', f'entropy < 0.01 for 3 steps', ents[-3:]))
if n >= 2 and all(e > 2.0 for e in ents[-2:]): alerts.append(('S2', 'entropy_explosion', f'entropy > 2.0 for 2 steps', ents[-2:]))
if n >= 3 and all(scores[i] == 0 and score_maxs[i] == 0 for i in range(n-3, n)): alerts.append(('S3', 'zero_reward_deadlock', f'all-zero reward for 3 steps', []))
if n >= 5 and all(abs(advs[i]) < 0.001 and score_maxs[i] > 0.5 for i in range(n-5, n)): alerts.append(('S4', 'grpo_signal_dead', f'advantage~0 with score/max>0.5 for 5 steps', []))
if n >= 3 and all(a > 0.5 for a in aborts[-3:]): alerts.append(('S5', 'abort_spike', f'aborted_ratio > 0.5 for 3 steps', aborts[-3:]))
if any(g > 100 for g in grads[-w:]): alerts.append(('S6', 'grad_explosion', f'grad_norm > 100', [max(grads[-w:])]))
if n >= 5 and all(abs(score_maxs[i] - score_mins[i]) < 0.001 for i in range(n-5, n)): alerts.append(('S7', 'reward_variance_zero', f'identical max/min for 5 steps', []))
print(f'\nDiagnosis ({n} steps):')
print(f'  reward: avg={sum(scores)/n:.4f} max={max(scores):.4f} min={min(scores):.4f}')
print(f'  grad:   avg={sum(grads)/n:.4f} max={max(grads):.4f}')
print(f'  entropy: {ents[0]:.3f}->{ents[-1]:.3f} avg={sum(ents)/n:.3f}')
print(f'  abort:  avg={sum(aborts)/n:.3f}')
print(f'  S0-S7 checks: ', end='')
statuses = []
for i in range(8):
    sid = f'S{i}'
    statuses.append(f'{sid}:ALERT' if any(a[0] == sid for a in alerts) else f'{sid}:ok')
print(' | '.join(statuses))
CRITICAL = {'S0', 'S1', 'S2', 'S3', 'S5', 'S6'}
WARN = {'S4', 'S7'}
critical_hits = [a for a in alerts if a[0] in CRITICAL]
warn_hits = [a for a in alerts if a[0] in WARN]
if critical_hits:
    preset_map = {'S0': 'lr_half', 'S1': 'entropy_bonus', 'S2': 'entropy_bonus', 'S3': 'diagnose', 'S5': 'diagnose', 'S6': 'lr_tenth'}
    hit = critical_hits[0]
    preset = preset_map.get(hit[0], 'diagnose')
    print(f'=== CIRCUIT_BREAK ===')
    print(f'circuit_break: true')
    print(f'abort_reason: {hit[0]}: {hit[2]}')
    print(f'fix_preset: {preset}')
    print(f'analysis_json: {run_dir}/analysis.json')
    print(f'=== END_CIRCUIT_BREAK ===')
elif warn_hits:
    for w in warn_hits:
        print(f'WARN: {w[0]}: {w[2]}')
"

